import{_ as e,o as i,c as a,ag as r}from"./chunks/framework.DXGyWiRo.js";const p=JSON.parse('{"title":"Pitching Logger","description":"","frontmatter":{},"headers":[],"relativePath":"scoring-games/pitching-logger.md","filePath":"scoring-games/pitching-logger.md"}'),o={name:"scoring-games/pitching-logger.md"};function l(n,t,s,h,c,d){return i(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="pitching-logger" tabindex="-1">Pitching Logger <a class="header-anchor" href="#pitching-logger" aria-label="Permalink to &quot;Pitching Logger&quot;">​</a></h1><p>The Pitching Logger captures every pitch thrown during a game or practice. Each pitch record includes the pitch type, location, and result.</p><h2 id="selecting-a-pitcher" tabindex="-1">Selecting a Pitcher <a class="header-anchor" href="#selecting-a-pitcher" aria-label="Permalink to &quot;Selecting a Pitcher&quot;">​</a></h2><p>Before logging pitches select the pitcher from your roster. The currently active pitcher is shown at the top of the screen.</p><p>To change pitchers tap <strong>Change Pitcher</strong>, select the new pitcher from the roster, and confirm. The previous pitcher&#39;s stats are locked and a new count begins for the incoming pitcher.</p><h2 id="logging-a-pitch" tabindex="-1">Logging a Pitch <a class="header-anchor" href="#logging-a-pitch" aria-label="Permalink to &quot;Logging a Pitch&quot;">​</a></h2><p>Each pitch requires three selections:</p><ol><li><strong>Pitch Type</strong> — select from your sport&#39;s pitch types</li><li><strong>Location</strong> — tap the zone on the pitch grid where the pitch crossed (or missed) the plate</li><li><strong>Result</strong> — select the outcome</li></ol><p>Tap <strong>Log Pitch</strong> to save. The pitch count and running stats update immediately.</p><h2 id="pitch-types" tabindex="-1">Pitch Types <a class="header-anchor" href="#pitch-types" aria-label="Permalink to &quot;Pitch Types&quot;">​</a></h2><p><strong>Baseball:</strong> Fastball, Curveball, Changeup, Slider, Cutter, Sinker, Splitter</p><p><strong>Softball:</strong> Fastball, Rise Ball, Drop Ball, Curveball, Changeup, Screwball</p><h2 id="location-grid" tabindex="-1">Location Grid <a class="header-anchor" href="#location-grid" aria-label="Permalink to &quot;Location Grid&quot;">​</a></h2><p>The location grid represents the strike zone and surrounding ball areas from the catcher&#39;s perspective.</p><p><strong>Strike zones</strong> (9 zones inside the strike zone):</p><ul><li>Three columns: Inside, Middle, Outside</li><li>Three rows: High, Middle, Low</li></ul><p><strong>Ball zones</strong> (outside the strike zone):</p><ul><li>Ball High Inside, Ball High Center, Ball High Outside</li><li>Ball Inside Center</li><li>Ball Low Left, Ball Low Center, Ball Low Right</li><li>Ball Outside High, Ball Outside Middle, Ball Outside Low</li></ul><h2 id="results" tabindex="-1">Results <a class="header-anchor" href="#results" aria-label="Permalink to &quot;Results&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Result</th><th>Description</th></tr></thead><tbody><tr><td>Strike</td><td>Any strike — swinging, looking, or foul</td></tr><tr><td>Ball</td><td>Ball outside the zone</td></tr><tr><td>Foul</td><td>Foul ball</td></tr><tr><td>Hit in Play</td><td>Ball put in play — app navigates to Fielding Logger</td></tr><tr><td>HBP</td><td>Hit by pitch</td></tr><tr><td>WP</td><td>Wild pitch</td></tr><tr><td>PB</td><td>Passed ball</td></tr></tbody></table><h2 id="strikeout-and-walk-buttons" tabindex="-1">Strikeout and Walk Buttons <a class="header-anchor" href="#strikeout-and-walk-buttons" aria-label="Permalink to &quot;Strikeout and Walk Buttons&quot;">​</a></h2><p>The <strong>K</strong> (strikeout) and <strong>BB</strong> (walk) buttons record the at-bat outcome on the most recent pitch record. They do <strong>not</strong> create a new pitch — they tag the last pitch as the at-bat ending pitch.</p><p>Always log the actual final pitch before tapping K or BB.</p><h2 id="pitcher-stats-display" tabindex="-1">Pitcher Stats Display <a class="header-anchor" href="#pitcher-stats-display" aria-label="Permalink to &quot;Pitcher Stats Display&quot;">​</a></h2><p>Running stats for the current pitcher appear at the bottom of the screen:</p><ul><li>Pitch count</li><li>Strikes and balls</li><li>K and BB counts</li><li>Innings pitched</li></ul><p><strong>Pitchers Used This Game</strong> shows the line for each pitcher who has appeared, including their final stats.</p><h2 id="era-display" tabindex="-1">ERA Display <a class="header-anchor" href="#era-display" aria-label="Permalink to &quot;ERA Display&quot;">​</a></h2><p>ERA is calculated using age-appropriate innings:</p><ul><li>8U–12U: ERA based on 6-inning games</li><li>13U and above, Middle School, High School: ERA based on 7-inning games</li></ul><p>The ERA label shows which calculation is being used (e.g. &quot;ERA (7-inn)&quot;).</p>',31)])])}const u=e(o,[["render",l]]);export{p as __pageData,u as default};
